import React from 'react';
import style from './ClassComponent.module.css';
import PropTypes from 'prop-types';

class ClassComponent extends React.Component {
    state = {
      result: 'Результат',
      userNumber: '',
      randomNumber:
          Math.floor(Math.random() * this.props.max - this.props.min) +
          this.props.min,
        count: 0
    };


  handleSubmit = e => {
    e.preventDefault();
    this.setState({
        count: this.state.count + 1
    });
    this.setState(state => {
        if (!state.userNumber) return {
            result: `Введите число`
        };

        if (state.userNumber > state.randomNumber) {
            return {
                result: `${state.userNumber} больше загаданного`,
            }
        }

        if (state.userNumber < state.randomNumber) {
            return {
                result: `${state.userNumber} меньше загаданного`,
            }
        }

        return {
            result: `Вы угадали, загаданное число ${state.userNumber},
            попыток ${this.state.count}`,
            gameOver: true
        }
    }, () => {
        this.setState({
            userNumber: '',
        })
    })
  };

  handleChange = (e) => {
    this.setState({
        userNumber: e.target.value,
    })
  }

    handlePlayAgain = () => {
        this.setState({
            result: 'Результат',
            userNumber: '',
            randomNumber: Math.floor(Math.random() * (this.props.max - this.props.min)) + this.props.min,
            count: 0,
            gameOver: false
        });
    }

    render() {
        return (
            <div className={style.game}>
                <p className={style.result}>{this.state.result}</p>

                {!this.state.gameOver && (
                    <form className={style.form} onSubmit={this.handleSubmit}>
                        <label className={style.label} htmlFor='user_number'>
                            Угадай число
                        </label>

                        <input
                            className={style.input}
                            type='number'
                            id='user_number'
                            onChange={this.handleChange}
                            value={this.state.userNumber}
                        />

                        <button className={style.btn}>Угадать</button>
                    </form>
                )}

                {this.state.gameOver && (
                    <button className={style.btn} onClick={this.handlePlayAgain}>
                        Сыграть ещё
                    </button>
                )}
            </div>
        );
    }
}

ClassComponent.propTypes = {
  min: PropTypes.number.isRequired,
  max: PropTypes.number.isRequired,
};

export default ClassComponent;
